CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, user_id VARCHAR(255) UNIQUE NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, referral_link VARCHAR(255) UNIQUE NOT NULL, referrer_id VARCHAR(255), balance DECIMAL(10, 2) DEFAULT 0, activation_status BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS activation_requests (id SERIAL PRIMARY KEY, user_id VARCHAR(255) NOT NULL, amount DECIMAL(10, 2) NOT NULL DEFAULT 10, proof_screenshot TEXT NOT NULL, admin_approved BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(user_id));
CREATE TABLE IF NOT EXISTS commissions (id SERIAL PRIMARY KEY, referrer_id VARCHAR(255) NOT NULL, referred_user_id VARCHAR(255) NOT NULL, level INTEGER NOT NULL, amount DECIMAL(10, 2) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (referrer_id) REFERENCES users(user_id), FOREIGN KEY (referred_user_id) REFERENCES users(user_id));
CREATE TABLE IF NOT EXISTS withdrawals (id SERIAL PRIMARY KEY, user_id VARCHAR(255) NOT NULL, amount DECIMAL(10, 2) NOT NULL, trc20_wallet_address VARCHAR(255) NOT NULL, admin_approval_status BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(user_id));
CREATE TABLE IF NOT EXISTS sessions (id SERIAL PRIMARY KEY, user_id VARCHAR(255) NOT NULL, session_token VARCHAR(255) UNIQUE NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, expires_at TIMESTAMP NOT NULL, FOREIGN KEY (user_id) REFERENCES users(user_id));